import { useEffect, useMemo, useState } from 'react';

import { WebProfileDropdown, WebSettingsPanel } from '@/components/web/WebOverlayPanels';
import { WebCoursesPanel, WebFlashcardsPanel, WebXpPanel } from '@/components/web/WebPanels';
import { WebTopBar } from '@/components/web/WebTopBar';
import { WEB_THEME } from '@/constants/theme';
import { DEFAULT_ACHIEVEMENTS, DEFAULT_COURSES, DEFAULT_USER } from '@/db/schema';
import type { Achievement, Course, UserProfile } from '@/types/evidex';

const STORAGE_KEYS = {
  courses: 'evidex.courses',
  darkMode: 'evidex.darkMode',
  user: 'evidex.user',
};

export default function HomePage() {
  const [courses, setCourses] = useState<Course[]>(DEFAULT_COURSES);
  const [user, setUser] = useState<UserProfile>(DEFAULT_USER);
  const [achievements] = useState<Achievement[]>(DEFAULT_ACHIEVEMENTS);
  const [settingsOpen, setSettingsOpen] = useState(false);
  const [profileOpen, setProfileOpen] = useState(false);
  const [darkMode, setDarkMode] = useState(false);

  useEffect(() => {
    const storedCourses = window.localStorage.getItem(STORAGE_KEYS.courses);
    const storedUser = window.localStorage.getItem(STORAGE_KEYS.user);
    const storedDarkMode = window.localStorage.getItem(STORAGE_KEYS.darkMode);

    if (!storedCourses) {
      window.localStorage.setItem(STORAGE_KEYS.courses, JSON.stringify(DEFAULT_COURSES));
    }
    if (!storedUser) {
      window.localStorage.setItem(STORAGE_KEYS.user, JSON.stringify(DEFAULT_USER));
    }

    setCourses(storedCourses ? JSON.parse(storedCourses) : DEFAULT_COURSES);
    setUser(storedUser ? JSON.parse(storedUser) : DEFAULT_USER);
    setDarkMode(storedDarkMode === 'true');
  }, []);

  useEffect(() => {
    window.localStorage.setItem(STORAGE_KEYS.courses, JSON.stringify(courses));
  }, [courses]);

  useEffect(() => {
    window.localStorage.setItem(STORAGE_KEYS.user, JSON.stringify(user));
  }, [user]);

  useEffect(() => {
    window.localStorage.setItem(STORAGE_KEYS.darkMode, darkMode ? 'true' : 'false');
  }, [darkMode]);

  const activeCourses = useMemo(() => courses.filter((course) => !course.completed), [courses]);
  const xpRatio = useMemo(() => Math.min(user.xp / Math.max(user.level * 150, 150), 1), [user]);
  const palette = useMemo(
    () =>
      darkMode
        ? {
            accent: '#314644',
            action: '#A4C488',
            border: '#2F3F46',
            card: '#1D2A30',
            soft: '#24353D',
            subtle: '#C1CCC4',
            text: '#F7F1E7',
            textMuted: '#C1CCC4',
          }
        : {
            accent: WEB_THEME.accent,
            action: WEB_THEME.action,
            border: WEB_THEME.border,
            card: WEB_THEME.card,
            soft: WEB_THEME.panelSoft,
            subtle: WEB_THEME.textSecondary,
            text: WEB_THEME.textPrimary,
            textMuted: WEB_THEME.textMuted,
          },
    [darkMode]
  );

  return (
    <main
      style={{
        background: darkMode
          ? 'radial-gradient(circle at top, #2A3A42 0%, #111B20 72%)'
          : 'radial-gradient(circle at top, #F9F5EC 0%, #EEF2EA 70%)',
        minHeight: '100vh',
        padding: 28,
      }}
    >
      <div style={{ margin: '0 auto', maxWidth: 1440, position: 'relative' }}>
        <WebTopBar
          onProfileEnter={() => setProfileOpen(true)}
          onProfileLeave={() => setProfileOpen(false)}
          onToggleProfileMenu={() => setProfileOpen((value) => !value)}
          onToggleSettings={() => setSettingsOpen((value) => !value)}
          onViewCourses={() => window.scrollTo({ behavior: 'smooth', top: 240 })}
          onViewSimulation={() => window.alert('La page simulation sera branchée prochainement.')}
          palette={palette}
        />

        <WebSettingsPanel
          darkMode={darkMode}
          onToggleDarkMode={() => setDarkMode((value) => !value)}
          open={settingsOpen}
          palette={palette}
        />
        <WebProfileDropdown open={profileOpen} palette={palette} />

        <section className="dashboard-grid" style={styles.grid}>
          <WebFlashcardsPanel
            onCreate={() => window.alert('La création sera reliée aux sujets des cours.')}
            palette={palette}
          />
          <WebCoursesPanel courses={activeCourses} palette={palette} />
          <WebXpPanel
            achievements={achievements}
            level={user.level}
            palette={palette}
            progressRatio={xpRatio}
            xp={user.xp}
          />
        </section>
      </div>

      <style jsx global>{`
        * {
          box-sizing: border-box;
        }

        body {
          margin: 0;
          font-family: "Trebuchet MS", "Segoe UI", sans-serif;
        }

        @media (max-width: 1120px) {
          .dashboard-grid {
            grid-template-columns: 1fr !important;
          }
        }
      `}</style>
    </main>
  );
}

const styles = {
  grid: {
    display: 'grid',
    gap: 20,
    gridTemplateColumns: '1.05fr 1.25fr 0.95fr',
  } as const,
};
