import type { CSSProperties } from 'react';

type Palette = {
  border: string;
  card: string;
  soft: string;
  text: string;
  textMuted: string;
};

export function WebSettingsPanel({
  darkMode,
  onToggleDarkMode,
  open,
  palette,
}: {
  darkMode: boolean;
  onToggleDarkMode: () => void;
  open: boolean;
  palette: Palette;
}) {
  if (!open) {
    return null;
  }

  return (
    <aside style={{ ...styles.panel, background: palette.card, borderColor: palette.border, left: 0 }}>
      <h3 style={{ ...styles.title, color: palette.text }}>Settings</h3>
      <button onClick={onToggleDarkMode} style={{ ...styles.toggle, background: palette.soft, color: palette.text }} type="button">
        Dark mode: {darkMode ? 'On' : 'Off'}
      </button>
      <div style={{ ...styles.item, background: palette.soft, color: palette.textMuted }}>Notifications</div>
      <div style={{ ...styles.item, background: palette.soft, color: palette.textMuted }}>Préférences</div>
      <div style={{ ...styles.item, background: palette.soft, color: palette.textMuted }}>Confidentialité</div>
    </aside>
  );
}

export function WebProfileDropdown({
  open,
  palette,
}: {
  open: boolean;
  palette: Palette;
}) {
  if (!open) {
    return null;
  }

  return (
    <aside style={{ ...styles.panel, background: palette.card, borderColor: palette.border, right: 0, width: 180 }}>
      <h3 style={{ ...styles.title, color: palette.text }}>Ilyas</h3>
      <button style={{ ...styles.toggle, background: palette.soft, color: palette.text }} type="button">
        Settings
      </button>
    </aside>
  );
}

const styles: Record<string, CSSProperties> = {
  panel: {
    border: '1px solid',
    borderRadius: 24,
    boxShadow: '0 18px 42px rgba(11, 27, 35, 0.10)',
    padding: 16,
    position: 'absolute',
    top: 96,
    width: 220,
    zIndex: 10,
  },
  title: {
    fontSize: 16,
    fontWeight: 800,
    margin: '0 0 12px',
  },
  toggle: {
    border: 0,
    borderRadius: 16,
    cursor: 'pointer',
    display: 'block',
    fontSize: 14,
    fontWeight: 700,
    marginBottom: 10,
    padding: '12px 14px',
    textAlign: 'left',
    width: '100%',
  },
  item: {
    borderRadius: 16,
    fontSize: 14,
    marginTop: 8,
    padding: '12px 14px',
  },
};
