import type { CSSProperties, ReactNode } from 'react';

import type { Achievement, Course } from '@/types/evidex';

type Palette = {
  action: string;
  border: string;
  card: string;
  soft: string;
  text: string;
  textMuted: string;
};

type CardProps = {
  action?: ReactNode;
  children: ReactNode;
  palette: Palette;
  title: string;
};

function Card({ action, children, palette, title }: CardProps) {
  return (
    <section style={{ ...styles.card, background: palette.card, borderColor: palette.border }}>
      <div style={styles.cardHeader}>
        <h2 style={{ ...styles.cardTitle, color: palette.text }}>{title}</h2>
        {action}
      </div>
      {children}
    </section>
  );
}

export function WebFlashcardsPanel({
  onCreate,
  palette,
}: {
  onCreate: () => void;
  palette: Palette;
}) {
  return (
    <Card
      action={
        <button onClick={onCreate} style={{ ...styles.pillButton, background: palette.action }} type="button">
          + Créer
        </button>
      }
      palette={palette}
      title="Cartes de révision"
    >
      <div style={{ ...styles.emptyBox, background: palette.soft }}>
        <p style={{ ...styles.emptyText, color: palette.textMuted }}>Sélectionne un sujet depuis les cours</p>
      </div>
    </Card>
  );
}

export function WebCoursesPanel({
  courses,
  palette,
}: {
  courses: Course[];
  palette: Palette;
}) {
  return (
    <Card palette={palette} title="Cours récents">
      <div style={styles.stack}>
        {courses.length > 0 ? (
          courses.map((course) => (
            <article key={course.id} style={{ ...styles.courseCard, background: palette.soft }}>
              <div style={styles.courseHeader}>
                <strong style={{ ...styles.courseName, color: palette.text }}>{course.name}</strong>
                <span style={{ ...styles.courseProgress, color: palette.textMuted }}>{course.progress}%</span>
              </div>
              <div style={styles.track}>
                <div style={{ ...styles.fill, background: palette.action, width: `${course.progress}%` }} />
              </div>
            </article>
          ))
        ) : (
          <div style={{ ...styles.emptyBox, background: palette.soft }}>
            <p style={{ ...styles.emptyText, color: palette.textMuted }}>Aucun cours non terminé.</p>
          </div>
        )}
      </div>
    </Card>
  );
}

export function WebXpPanel({
  achievements,
  level,
  palette,
  progressRatio,
  xp,
}: {
  achievements: Achievement[];
  level: number;
  palette: Palette;
  progressRatio: number;
  xp: number;
}) {
  return (
    <Card
      action={
        <a
          href="/achievements"
          style={{ ...styles.pillButton, background: palette.action, display: 'inline-block', textDecoration: 'none' }}
        >
          Voir Achievements
        </a>
      }
      palette={palette}
      title="XP & Niveau"
    >
      <div style={styles.stack}>
        <div style={styles.track}>
          <div style={{ ...styles.fill, background: palette.action, width: `${Math.round(progressRatio * 100)}%` }} />
        </div>
        <div style={styles.statsGrid}>
          <div style={{ ...styles.statBox, background: palette.soft }}>
            <span style={{ ...styles.statLabel, color: palette.textMuted }}>Current XP</span>
            <strong style={{ ...styles.statValue, color: palette.text }}>{xp}</strong>
          </div>
          <div style={{ ...styles.statBox, background: palette.soft }}>
            <span style={{ ...styles.statLabel, color: palette.textMuted }}>Current Level</span>
            <strong style={{ ...styles.statValue, color: palette.text }}>{level}</strong>
          </div>
        </div>
        <div style={{ ...styles.badgeStrip, background: palette.soft, color: palette.text }}>
          {achievements.length} achievements préparés
        </div>
      </div>
    </Card>
  );
}

